/* default variables */
:root {	
	--bct-blur: 10px;

	--bct-tab-toolbar-bg: #000000AA;


	--bct-bg: #00000088;
	--bct-color: #F2F2F2;


	--bct-e-urlbar-bg: var(--bct-bg);
	--bct-e-popups-bg: var(--bct-bg);


	--bct-w-sidebar-bg: var(--bct-bg);
	--bct-w-sidebar-color: var(--bct-color);

